import math

def circulo(r):
    area = math.pi * r ** 2
    perimetro = 2 * math.pi * r
    return (area, perimetro)

def retangulo(l, a):
    area = l * a
    perimetro = 2 * (l + a)
    return (area, perimetro)

def triangulo(b, h, l1, l2, l3):
    area = (b * h) / 2
    perimetro = l1 + l2 + l3
    return (area, perimetro)

