import time
import functools

def fibonacci_simples(n):
    if n <= 1:
        return n
    return fibonacci_simples(n - 1) + fibonacci_simples(n - 2)

@functools.lru_cache(maxsize=None)
def fibonacci_cache(n):
    if n <= 1:
        return n
    return fibonacci_cache(n - 1) + fibonacci_cache(n - 2)

