def media(lista):
    return sum(lista) / len(lista)

def mediana(lista):
    ordenada = sorted(lista)
    n = len(ordenada)
    if n % 2 == 1:
        return ordenada[n // 2]
    return (ordenada[n // 2 - 1] + ordenada[n // 2]) / 2

def moda(lista):
    contagem = {}
    for valor in lista:
        contagem[valor] = contagem.get(valor, 0) + 1
    max_freq = max(contagem.values())
    return [v for v, f in contagem.items() if f == max_freq]

def desvio_padrao(lista):
    m = media(lista)
    soma = sum((x - m) ** 2 for x in lista)
    return (soma / len(lista)) ** 0.5

def resumo(lista):
    return {
        "media": media(lista),
        "mediana": mediana(lista),
        "moda": moda(lista),
        "desvio_padrao": desvio_padrao(lista),
    }

entrada = input("Lista: ")
