def pa_termo(a1, r, n):
    return a1 + (n - 1) * r

def pa_soma(a1, r, n):
    return n * (a1 + pa_termo(a1, r, n)) // 2

def pg_termo(a1, q, n):
    return a1 * q ** (n - 1)

def pg_soma(a1, q, n):
    if q == 1:
        return a1 * n
    return a1 * (q ** n - 1) // (q - 1)

def identificar_sequencia(lista):
    if len(lista) < 2:
        return "Sequencia muito curta"
    d = lista[1] - lista[0]
    eh_pa = all(lista[i] - lista[i - 1] == d for i in range(1, len(lista)))
    if lista[0] != 0 and all(lista[i - 1] != 0 for i in range(1, len(lista))):
        q = lista[1] / lista[0]
        eh_pg = all(abs(lista[i] / lista[i - 1] - q) < 1e-9 for i in range(1, len(lista)))
    else:
        eh_pg = False
    if eh_pa:
        return f"PA com razao r={d}"
    if eh_pg:
        return f"PG com razao q={q}"
    return "Nenhuma"

