import re

def contar_palavras(texto):
    return len(texto.split())

def eh_palindromo(texto):
    limpo = re.sub(r"[^a-zA-Z]", "", texto).lower()
    return limpo == limpo[::-1]

def pig_latin(texto):
    palavras = texto.split()
    resultado = []
    for p in palavras:
        if p and p[0].lower() in "aeiou":
            resultado.append(p + "ay")
        else:
            resultado.append(p[1:] + p[0] + "ay" if p else p)
    return " ".join(resultado)

